# ║ Path(from_PolynomialRing(K1,), id) over Any                ║
# ╠════════════════════════════════════════════════════════════╣
# ║ from_PolynomialRing : Any → Any                            ║
# ╠════════════════════════════════════════════════════════════╣
# ║ Trusted:                                                   ║
